div.style:
font-family: 'Helvetica Neue', Arial, sans-serif;
font-size: 12px;
color: #2C3E50;
margin: 0;
padding: 0;
position: relative;

h1.style:
font-size: 22px;
font-weight: 900;
color: #1C2B4A;
letter-spacing: 4px;
text-transform: uppercase;
margin: 0 0 6px;

div.style:
position:fixed; bottom:0; left:0; right:0;
padding: 10px 32px;
border-top: 1px solid #E8EAED;
display:flex; justify-content:space-between; align-items:center;
font-size:9px; color:#95A5A6;

position:absolute; bottom:-20px; right:-20px;
width:80px; height:80px;
background:#1C2B4A;
transform:rotate(45deg);
opacity:0.85;

position:absolute; bottom:-30px; right:20px;
width:60px; height:60px;
background:#C0392B;
transform:rotate(45deg);
opacity:0.75;

background:#1C2B4A;
color:white;
border-radius:6px;
padding:12px 20px;
display:flex;
justify-content:space-between;
align-items:center;
margin-bottom:18px;

display:inline-block;
padding:4px 14px;
border-radius:20px;
font-size:10px;
font-weight:700;
background:#C0392B;

font-size:9px; font-weight:700; color:#C0392B;
letter-spacing:1.5px; border-bottom:1px solid #E8EAED;
padding-bottom:6px; margin-bottom:10px;

background:#F5F6F8;
border:1px solid #E8EAED;
border-radius:6px;
padding:8px 14px;
text-align:center;
min-width:80px;

font-size:9px; font-weight:700; color:#C0392B;
letter-spacing:1.5px; border-bottom:1px solid #E8EAED;
padding-bottom:6px; margin-bottom:10px;

background:#F5F6F8;
border:1px solid #E8EAED;
border-radius:6px;
padding:12px 16px;
font-size:11px;
line-height:1.7;
color:#4A5568;

font-size:9px; font-weight:700; color:#C0392B;
letter-spacing:1.5px; border-bottom:1px solid #E8EAED;
padding-bottom:6px; margin-bottom:10px;

background:#F5F6F8;
border:1px solid #E8EAED;
border-radius:6px;
padding:14px 18px;
